  "description": "A modern, responsive single-page application featuring three distinct functional workspaces: an Analytics Dashboard, an AI-powered Creative Assistant, and a Multimedia Gallery. Seamlessly switch contexts with a high-performance tabbed interface."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { LucideIcon } from 'lucide-react';

export enum TabId {
  DASHBOARD = 'DASHBOARD',
  ASSISTANT = 'ASSISTANT',
  GALLERY = 'GALLERY'
}

export interface TabConfig {
  id: TabId;
  label: string;
  icon: LucideIcon;
  description: string;
}

export interface ChartDataPoint {
  name: string;
  value: number;
  secondary: number;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
  isError?: boolean;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const API_KEY = process.env.API_KEY || '';

// Initialize the client strictly according to guidelines
// We create a function to get the client to ensure we check for the key at runtime
const getClient = (): GoogleGenAI => {
  if (!API_KEY) {
    console.warn("API Key is missing. AI features will not function correctly.");
  }
  return new GoogleGenAI({ apiKey: API_KEY });
};

export const generateAssistantResponse = async (
  prompt: string, 
  onChunk: (text: string) => void
): Promise<string> => {
  if (!API_KEY) {
    throw new Error("API Key is not configured.");
  }

  const ai = getClient();
  let fullText = "";

  try {
    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        systemInstruction: "You are a helpful, concise, and witty AI assistant integrated into a modern web application.",
      }
    });

    for await (const chunk of responseStream) {
      // Correctly cast and access text property
      const c = chunk as GenerateContentResponse;
      const text = c.text;
      if (text) {
        fullText += text;
        onChunk(fullText);
      }
    }

    return fullText;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React from 'react';
import { TabConfig, TabId } from '../types';

interface TabNavigationProps {
  tabs: TabConfig[];
  activeTab: TabId;
  onTabChange: (id: TabId) => void;
}

export const TabNavigation: React.FC<TabNavigationProps> = ({ tabs, activeTab, onTabChange }) => {
  return (
    <nav className="flex space-x-1 bg-surface/50 p-2 rounded-xl backdrop-blur-md border border-white/5 shadow-lg mb-8 overflow-x-auto">
      {tabs.map((tab) => {
        const isActive = activeTab === tab.id;
        const Icon = tab.icon;

        return (
          <button
            key={tab.id}
            onClick={() => onTabChange(tab.id)}
            className={`
              flex-1 flex items-center justify-center gap-2 px-6 py-3 rounded-lg text-sm font-medium transition-all duration-200 ease-in-out whitespace-nowrap
              ${isActive 
                ? 'bg-primary text-white shadow-md shadow-primary/20 scale-[1.02]' 
                : 'text-slate-400 hover:text-white hover:bg-white/5'
              }
            `}
            aria-current={isActive ? 'page' : undefined}
          >
            <Icon size={18} className={isActive ? 'animate-pulse' : ''} />
            <span>{tab.label}</span>
          </button>
        );
      })}
    </nav>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles, Loader2, AlertCircle } from 'lucide-react';
import { ChatMessage } from '../types';
import { generateAssistantResponse } from '../services/geminiService';

export const AssistantView: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: "Hello! I'm your Gemini-powered assistant. How can I help you draft content or analyze data today?",
      timestamp: new Date()
    }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSendMessage = async () => {
    if (!inputValue.trim() || isLoading) return;

    const userMessage: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: inputValue,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputValue('');
    setIsLoading(true);

    // Create a placeholder for the AI response
    const botMessageId = (Date.now() + 1).toString();
    const initialBotMessage: ChatMessage = {
      id: botMessageId,
      role: 'model',
      text: '', // Start empty for streaming
      timestamp: new Date()
    };

    setMessages(prev => [...prev, initialBotMessage]);

    try {
      await generateAssistantResponse(userMessage.text, (chunkedText) => {
        setMessages(prev => prev.map(msg => 
          msg.id === botMessageId ? { ...msg, text: chunkedText } : msg
        ));
      });
    } catch (error) {
      setMessages(prev => prev.map(msg => 
        msg.id === botMessageId 
          ? { ...msg, text: "I'm sorry, I encountered an issue connecting to my brain (API). Please check your API key configuration.", isError: true } 
          : msg
      ));
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="h-[calc(100vh-12rem)] flex flex-col bg-surface border border-white/5 rounded-2xl shadow-2xl overflow-hidden animate-fade-in">
      {/* Header */}
      <div className="p-4 border-b border-white/10 flex items-center gap-3 bg-slate-800/50 backdrop-blur-sm">
        <div className="p-2 bg-gradient-to-tr from-indigo-500 to-purple-500 rounded-lg">
          <Sparkles className="text-white" size={20} />
        </div>
        <div>
          <h2 className="text-lg font-semibold text-white">GenAI Workspace</h2>
          <p className="text-xs text-slate-400">Powered by Gemini 2.5 Flash</p>
        </div>
      </div>

      {/* Chat Area */}
      <div className="flex-1 overflow-y-auto p-6 space-y-6 scroll-smooth">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex items-start gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}
          >
            <div className={`
              flex-shrink-0 w-10 h-10 rounded-full flex items-center justify-center
              ${msg.role === 'user' ? 'bg-slate-700' : 'bg-indigo-600'}
            `}>
              {msg.role === 'user' ? <User size={20} /> : <Bot size={20} />}
            </div>

            <div className={`
              max-w-[80%] rounded-2xl p-4 shadow-sm
              ${msg.role === 'user' 
                ? 'bg-slate-700 text-white rounded-tr-none' 
                : 'bg-slate-800/80 border border-white/5 text-slate-200 rounded-tl-none'
              }
              ${msg.isError ? 'border-red-500/50 bg-red-900/10' : ''}
            `}>
              {msg.isError && <AlertCircle className="text-red-400 mb-2" size={16} />}
              <p className="whitespace-pre-wrap leading-relaxed text-sm">
                {msg.text || <span className="animate-pulse">Thinking...</span>}
              </p>
            </div>
          </div>
        ))}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-slate-800/50 border-t border-white/10">
        <div className="flex gap-2">
          <input
            type="text"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
            placeholder="Ask anything (e.g., 'Draft a marketing email for a coffee shop')"
            className="flex-1 bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all"
            disabled={isLoading}
          />
          <button
            onClick={handleSendMessage}
            disabled={isLoading || !inputValue.trim()}
            className={`
              px-6 rounded-xl flex items-center justify-center transition-all duration-200
              ${isLoading || !inputValue.trim() 
                ? 'bg-slate-800 text-slate-500 cursor-not-allowed' 
                : 'bg-indigo-600 hover:bg-indigo-500 text-white hover:scale-105 active:scale-95 shadow-lg shadow-indigo-500/20'
              }
            `}
          >
            {isLoading ? <Loader2 className="animate-spin" size={20} /> : <Send size={20} />}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { LayoutDashboard, Sparkles, Image as ImageIcon } from 'lucide-react';
import { TabNavigation } from './components/TabNavigation';
import { DashboardView } from './views/DashboardView';
import { AssistantView } from './views/AssistantView';
import { GalleryView } from './views/GalleryView';
import { TabConfig, TabId } from './types';

const TABS: TabConfig[] = [
  { 
    id: TabId.DASHBOARD, 
    label: 'Dashboard', 
    icon: LayoutDashboard,
    description: "Overview of system metrics"
  },
  { 
    id: TabId.ASSISTANT, 
    label: 'Smart Assistant', 
    icon: Sparkles,
    description: "Gemini-powered AI tools"
  },
  { 
    id: TabId.GALLERY, 
    label: 'Media Gallery', 
    icon: ImageIcon,
    description: "Visual asset collection"
  },
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabId>(TabId.DASHBOARD);

  const renderContent = () => {
    switch (activeTab) {
      case TabId.DASHBOARD:
        return <DashboardView />;
      case TabId.ASSISTANT:
        return <AssistantView />;
      case TabId.GALLERY:
        return <GalleryView />;
      default:
        return <DashboardView />;
    }
  };

  return (
    <div className="min-h-screen bg-background text-slate-200 selection:bg-indigo-500/30">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Top Header */}
        <div className="flex items-center justify-between mb-8">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 bg-gradient-to-br from-indigo-500 to-pink-500 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
               <span className="text-white font-bold text-xl">N</span>
             </div>
             <div>
                <h1 className="text-2xl font-bold text-white tracking-tight">TriView Nexus</h1>
                <p className="text-xs text-slate-500 font-medium">Single Page Application Workspace</p>
             </div>
          </div>
          <div className="hidden sm:flex items-center gap-4">
             <div className="px-3 py-1 bg-surface border border-white/5 rounded-full text-xs text-slate-400 flex items-center gap-2">
               <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
               System Online
             </div>
          </div>
        </div>

        {/* Navigation Tabs */}
        <TabNavigation 
          tabs={TABS} 
          activeTab={activeTab} 
          onTabChange={setActiveTab} 
        />

        {/* Dynamic Content Area */}
        <main className="min-h-[600px] relative">
           {renderContent()}
        </main>

        {/* Footer */}
        <footer className="mt-20 border-t border-white/5 pt-8 text-center text-slate-500 text-sm">
          <p>&copy; {new Date().getFullYear()} TriView Nexus. Built with React, Tailwind & Gemini.</p>
        </footer>
      </div>
    </div>
  );
};

export default App;

